CREATE TABLE `dividend_info` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'PK: 배당 정보 ID',
  `symbol` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '종목 코드 (예: AAPL, PFE)',
  `dividend_date` date NOT NULL COMMENT '배당 기준일',
  `dividend_amount` decimal(14,8) NOT NULL COMMENT '배당금액 (주당)',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=16316 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='배당 정보 테이블';
