DROP TABLE IF EXISTS `market_statistics`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `market_statistics` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '시장 통계 고유 ID',
  `stat_date` date NOT NULL COMMENT '통계 기준 날짜',
  `stat_time` time DEFAULT NULL COMMENT '통계 기준 시간',
  `market_name` varchar(100) NOT NULL COMMENT '시장명 (예: S&P 500, KOSPI, NASDAQ)',
  `description` text COMMENT '시장 상황 설명',
  `index_value` decimal(12,2) DEFAULT NULL COMMENT '지수 값',
  `change_percentage` decimal(5,2) DEFAULT NULL COMMENT '변동률 (%)',
  `change_direction` enum('up','down','neutral') DEFAULT NULL COMMENT '변동 방향 (상승/하락/보합)',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '레코드 생성 시각',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '레코드 수정 시각',
  PRIMARY KEY (`id`),
  KEY `idx_stat_date` (`stat_date`) COMMENT '날짜 기준 조회 최적화',
  KEY `idx_market_name` (`market_name`) COMMENT '시장명 기준 조회 최적화'
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='주요 시장 지수의 일별 통계 정보';
/*!40101 SET character_set_client = @saved_cs_client */;

