/*!40000 ALTER TABLE `market_statistics` DISABLE KEYS */;
INSERT INTO `market_statistics` VALUES (1,'2025-10-29','16:00:00','S&P 500','S&P 500은 소비자 신뢰 지수 개선과 빅테크 실적로 0.8% 상승 마감. 연준의 완화적 통화정책 유지 시사 투자 심리 개선.',5234.50,0.80,'up','2025-11-10 23:34:49','2025-11-10 23:34:49'),(2,'2025-10-29','15:30:00','KOSPI','코스피 지수는 반도체 수출 호조와 외국인 매수세로 1.2% 상승',2645.30,1.20,'up','2025-11-10 23:34:49','2025-11-10 23:34:49'),(3,'2025-10-29','16:00:00','NASDAQ','나스닥 지수는 AI 관련 기술주 강세로 1.5% 상승',16523.45,1.50,'up','2025-11-10 23:34:49','2025-11-10 23:34:49'),(4,'2025-10-28','16:00:00','S&P 500','연준 금리 동결 결정에 시장 혼조세',5193.20,-0.30,'down','2025-11-10 23:34:49','2025-11-10 23:34:49'),(5,'2025-10-28','15:30:00','KOSPI','중국 경기 둔화 우려로 하락 마감',2613.85,-0.80,'down','2025-11-10 23:34:49','2025-11-10 23:34:49');
/*!40000 ALTER TABLE `market_statistics` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `news`
