DROP TABLE IF EXISTS `news`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `news` (
  `news_id` bigint NOT NULL AUTO_INCREMENT COMMENT '뉴스 고유 ID',
  `title` varchar(500) NOT NULL COMMENT '뉴스 제목',
  `content` text COMMENT '뉴스 본문 내용',
  `summary` text COMMENT '뉴스 요약',
  `published_date` date NOT NULL COMMENT '발행 날짜',
  `published_time` time DEFAULT NULL COMMENT '발행 시간',
  `news_type` enum('positive','negative','neutral') DEFAULT 'neutral' COMMENT '뉴스 유형 (긍정/부정/중립)',
  `source` varchar(200) DEFAULT NULL COMMENT '뉴스 출처',
  `source_url` varchar(1000) DEFAULT NULL COMMENT '원문 URL',
  `impact_level` enum('high','medium','low') DEFAULT NULL COMMENT '시장 영향도 (높음/중간/낮음)',
  `view_count` int DEFAULT '0' COMMENT '조회수',
  `is_featured` tinyint(1) DEFAULT '0' COMMENT '주요 뉴스 여부 (메인 노출)',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '레코드 생성 시각',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '레코드 수정 시각',
  PRIMARY KEY (`news_id`),
  KEY `idx_published_date` (`published_date`) COMMENT '발행일 기준 조회 최적화',
  KEY `idx_news_type` (`news_type`) COMMENT '뉴스 유형 기준 조회 최적화',
  KEY `idx_featured` (`is_featured`) COMMENT '주요 뉴스 필터링 최적화'
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='시장 관련 주요 뉴스 데이터';
/*!40101 SET character_set_client = @saved_cs_client */;

