/*!40000 ALTER TABLE `news` DISABLE KEYS */;
INSERT INTO `news` VALUES (1,'NVIDIA, AI 칩 수요 급증으로 분기 실적 예상치 상회','NVIDIA가 3분기 실적 발표에서 매출 가이던스를 상향 조정하며 AI 칩 수요가 지속적으로 증가하고 있음을 시사. 데이터센터 부문 매출이 200% 이상 증가.','NVIDIA가 3분기 실적 발표에서 매출 가이던스를 상향 조정하며 AI 칩 수요가 지속적으로 증가하고 있음을 시사.','2025-10-29','09:30:00','positive','Reuters','https://reuters.com/nvidia-earnings','high',15234,1,'2025-11-10 23:34:49','2025-11-10 23:34:49'),(2,'소비자물가지수(CPI) 전월 대비 0.2% 상승, 인플레이션 둔화 지속','9월 CPI가 예상치와 일치하며 인플레이션 둔화세가 이어지고 있다는 것이 확인됨. 연준의 금리 인상 압력 완화 전망.','9월 CPI가 예상치와 일치하며 인플레이션 둔화세가 확인. 연준의 금리 인상 압력이 완화될 것으로 전망.','2025-10-29','08:30:00','positive','Bloomberg','https://bloomberg.com/cpi-report','high',12856,1,'2025-11-10 23:34:49','2025-11-10 23:34:49'),(3,'원유 가격 배럴당 $85 돌파, 중동 긴장 고조','중동 지역의 지정학적 리스크 증가로 WTI 원유 가격이 급등. 에너지 섹터 주가는 상승했으나, 전체 시장에는 부담 요인으로 작용.','중동 지역의 지정학적 리스크로 WTI 원유 가격이 배럴당 $85를 돌파하며 급등.','2025-10-28','14:20:00','negative','Financial Times','https://ft.com/oil-prices','medium',9845,1,'2025-11-10 23:34:49','2025-11-10 23:34:49'),(4,'대형 은행들 3분기 순이익 15% 증가','JPMorgan, Bank of America 등 주요 은행들이 3분기 실적 발표에서 예상을 뛰어넘는 순이익 발표. 금융 섹터 전반적인 상승 주도.','JPMorgan, Bank of America 등 주요 은행들이 3분기 순이익 15% 증가하며 금융 섹터 상승 주도.','2025-10-27','10:15:00','positive','CNBC','https://cnbc.com/bank-earnings','medium',8234,0,'2025-11-10 23:34:49','2025-11-10 23:34:49'),(5,'테슬라, 새로운 전기차 모델 출시 발표','테슬라가 2026년 출시 예정인 보급형 전기차 모델을 발표하며 주가 5% 상승. 전기차 시장 확대 기대감 증폭.','테슬라가 2026년 보급형 전기차 모델 출시를 발표하며 주가 5% 상승.','2025-10-26','11:00:00','positive','TechCrunch','https://techcrunch.com/tesla-new-model','low',6543,0,'2025-11-10 23:34:49','2025-11-10 23:34:49');
/*!40000 ALTER TABLE `news` ENABLE KEYS */;
UNLOCK TABLES;

