--
-- Table structure for table `tbl_guru`
--

DROP TABLE IF EXISTS `tbl_guru`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_guru` (
  `GURU_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '고유 식별자',
  `GURU_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '구루 식별 코드 (예: BRK, PSC)',
  `INVESTOR_NM` varchar(150) COLLATE utf8mb4_general_ci NOT NULL COMMENT '투자자 영문명 (예: Warren Buffett)',
  `INVESTOR_KO_NM` varchar(150) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '투자자 한글명 (예: 워런 버핏)',
  `INVESTOR_NICKNAME` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '투자자 한 단어 별칭 (예: 오마하의 현인, 숏의 제왕)',
  `INVEST_PHILOSOPHY` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '투자 철학',
  `FAMOUS_QUOTE` varchar(1000) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '투자 대가의 명언',
  `REG_DT` datetime DEFAULT NULL COMMENT '데이터 등록 일시',
  PRIMARY KEY (`GURU_ID`),
  UNIQUE KEY `UK_GURU_CD` (`GURU_CD`)
) ENGINE=InnoDB AUTO_INCREMENT=20 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='구루(저명 투자자) 기본 정보';
