DROP TABLE IF EXISTS `tbl_guru_portfolios`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_guru_portfolios` (
  `GURU_PORTFOLIOS_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '고유 식별자',
  `GURU_ID` bigint NOT NULL COMMENT 'tbl_guru 참조 식별자',
  `ISSUER_NM` varchar(200) COLLATE utf8mb4_general_ci NOT NULL COMMENT '보유 종목 회사명',
  `TICKER` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '종목 티커 심볼 (예: AAPL)',
  `RANK_NO` int DEFAULT NULL COMMENT '해당 투자자 포트폴리오 내 보유 순위',
  `PORTFOLIO_PCT` decimal(5,2) DEFAULT NULL COMMENT '포트폴리오 내 비중 (%)',
  `REPORT_DATE` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '보고 기준일 (예: Q1 2024)',
  `REG_DT` datetime DEFAULT NULL COMMENT '데이터 등록 일시',
  PRIMARY KEY (`GURU_PORTFOLIOS_ID`),
  UNIQUE KEY `UK_GURU_HOLDING` (`GURU_ID`,`TICKER`,`REPORT_DATE`)
) ENGINE=InnoDB AUTO_INCREMENT=1082 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='구루(저명 투자자) 포트폴리오 보유 현황';
/*!40101 SET character_set_client = @saved_cs_client */;

