--
-- Table structure for table `tbl_guru_recent_activity`
--

DROP TABLE IF EXISTS `tbl_guru_recent_activity`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_guru_recent_activity` (
  `ACTIVITY_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '고유 식별자',
  `GURU_CD` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '투자자 고유 코드 (tbl_guru.GURU_CD)',
  `ACTIVITY_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '매매 유형 (BUY: 신규매수 / SELL: 매도 / ADD: 추가매수 / TRIM: 일부매도)',
  `ISSUER_NM` varchar(200) COLLATE utf8mb4_general_ci NOT NULL COMMENT '거래 종목 회사명',
  `TICKER` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '종목 티커 심볼 (예: AAPL)',
  `ACTIVITY_DATE` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '매매 발생 분기 (예: Q1 2024)',
  `ACTIVITY_YEAR` smallint NOT NULL COMMENT '매매 발생 연도 (예: 2025)',
  `ACTIVITY_QTR` tinyint NOT NULL COMMENT '매매 발생 분기 (1~4)',
  `CHANGE_PCT` decimal(10,2) DEFAULT NULL COMMENT '포지션 변동 비율 (%) - 양수: 증가, 음수: 감소',
  `NOTES` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '비고 및 추가 메모',
  `REG_DT` datetime DEFAULT NULL COMMENT '데이터 등록 일시',
  PRIMARY KEY (`ACTIVITY_ID`),
  UNIQUE KEY `UK_GURU_ACTIVITY` (`GURU_CD`,`TICKER`,`ACTIVITY_DATE`,`ACTIVITY_TYPE`)
) ENGINE=InnoDB AUTO_INCREMENT=5301 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='구루(저명 투자자) 최근 매매 활동 내역';
/*!40101 SET character_set_client = @saved_cs_client */;

