DROP TABLE IF EXISTS `tbl_portfolio`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_portfolio` (
  `PORTFOLIO_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '포트폴리오ID',
  `USER_ID` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '사용자ID',
  `PORTFOLIO_NM` varchar(200) COLLATE utf8mb4_general_ci NOT NULL COMMENT '포트폴리오명',
  `PORTFOLIO_DESC` text COLLATE utf8mb4_general_ci COMMENT '포트폴리오 설명',
  `BASE_CURRENCY` varchar(10) COLLATE utf8mb4_general_ci DEFAULT 'USD' COMMENT '기준통화',
  `USE_YN` char(1) COLLATE utf8mb4_general_ci DEFAULT 'Y' COMMENT '사용여부',
  `REG_DT` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_DT` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`PORTFOLIO_ID`),
  KEY `IDX_USER_ID` (`USER_ID`)
) ENGINE=InnoDB AUTO_INCREMENT=14 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='포트폴리오';
