CREATE TABLE `tbl_portfolio_item` (
  `ITEM_ID` bigint NOT NULL AUTO_INCREMENT COMMENT '항목ID',
  `PORTFOLIO_ID` bigint NOT NULL COMMENT '포트폴리오ID',
  `STOCK_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '종목코드',
  `HOLD_QTY` decimal(18,4) NOT NULL COMMENT '보유수량',
  `BUY_PRICE` decimal(18,4) NOT NULL COMMENT '매수단가',
  `BUY_DT` date NOT NULL COMMENT '매수일자',
  `BUY_AMOUNT` decimal(18,4) DEFAULT NULL COMMENT '매수금액 (보유수량 * 매수단가)',
  `CURRENCY` varchar(10) COLLATE utf8mb4_general_ci DEFAULT 'USD' COMMENT '통화',
  `MEMO` text COLLATE utf8mb4_general_ci COMMENT '메모',
  `USE_YN` char(1) COLLATE utf8mb4_general_ci DEFAULT 'Y' COMMENT '사용여부',
  `REG_DT` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `UPD_DT` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  PRIMARY KEY (`ITEM_ID`),
  KEY `IDX_PORTFOLIO_ID` (`PORTFOLIO_ID`),
  KEY `IDX_STOCK_CD` (`STOCK_CD`),
  KEY `IDX_BUY_DT` (`BUY_DT`)
) ENGINE=InnoDB AUTO_INCREMENT=55 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='포트폴리오 종목';
