DROP TABLE IF EXISTS `tbl_stock_info`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_stock_info` (
  `STOCK_CD` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '종목코드 (예: AAPL, 005930)',
  `STOCK_NM` varchar(200) COLLATE utf8mb4_general_ci NOT NULL COMMENT '종목명',
  `STOCK_NM_EN` varchar(200) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '종목명(영문)',
  `MARKET_TYPE` varchar(20) COLLATE utf8mb4_general_ci NOT NULL COMMENT '시장구분 (US, KR, etc)',
  `EXCHANGE` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '거래소 (NASDAQ, NYSE, KOSPI, KOSDAQ)',
  `SECTOR` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '섹터 (Technology, Healthcare, etc)',
  `INDUSTRY` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '산업군 (보다 세부적인 분류)',
  `LISTING_DT` date DEFAULT NULL COMMENT '상장일',
  `COUNTRY` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '국가',
  `USE_YN` char(1) COLLATE utf8mb4_general_ci DEFAULT 'Y' COMMENT '사용여부',
  `REG_DT` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `REG_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '등록자ID',
  `UPD_DT` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  `UPD_ID` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '수정자ID',
  PRIMARY KEY (`STOCK_CD`),
  KEY `IDX_STOCK_NM` (`STOCK_NM`),
  KEY `IDX_SECTOR` (`SECTOR`),
  KEY `IDX_MARKET_TYPE` (`MARKET_TYPE`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='종목 마스터 정보';
/*!40101 SET character_set_client = @saved_cs_client */;

