  `REG_DT` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  PRIMARY KEY (`PRICE_ID`),
  UNIQUE KEY `UK_STOCK_PRICE` (`STOCK_CD`,`PRICE_DT`),
  KEY `IDX_PRICE_DT` (`PRICE_DT`)
) ENGINE=InnoDB AUTO_INCREMENT=4521 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='주가 이력';
