--
-- Table structure for table `tbl_survey`
--

DROP TABLE IF EXISTS `tbl_survey`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_survey` (
  `survey_id` bigint NOT NULL AUTO_INCREMENT COMMENT '설문 ID',
  `survey_name` varchar(255) COLLATE utf8mb4_general_ci NOT NULL COMMENT '설문 이름',
  `description` text COLLATE utf8mb4_general_ci COMMENT '설문 설명',
  `survey_type_code` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '설문 유형 코드 - SURVEY_TYPE.RISK_PROFILE 등',
  `reg_dt` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  `upd_dt` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '수정일시',
  `use_yn` char(1) COLLATE utf8mb4_general_ci DEFAULT 'N' COMMENT '사용 여부',
  PRIMARY KEY (`survey_id`),
  KEY `idx_survey_type_code` (`survey_type_code`)
) ENGINE=InnoDB AUTO_INCREMENT=18 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='설문 마스터 테이블';
/*!40101 SET character_set_client = @saved_cs_client */;

