INSERT INTO `tbl_survey` VALUES (10,'나의 투자 성향 분석','수익 추구, 리스크 허용, 장기 투자, 분산 투자 4가지 축을 기반으로 투자 성향을 분석하는 설문입니다.','RISK_PROFILE','2026-03-08 23:42:33','2026-03-08 23:42:33','Y'),(11,'시장 심리 트렌드_20260308','현재 시장에서 주목받고 있는 주요 이슈에 대한 투자자 심리(낙관/중립/비관)를 측정하는 설문입니다.','MARKET_SENTIMENT','2026-03-08 23:42:36','2026-03-08 23:42:36','Y'),(12,'선호 섹터 분석','기술주·헬스케어·소비재·에너지·금융 등 주요 섹터에 대한 선호도와 투자 비중, 향후 전망을 분석하는 설문입니다.','SECTOR_PREFERENCE','2026-03-08 23:42:38','2026-03-08 23:42:38','Y'),(13,'이번 주 투자자 심리_2026W10','매주 주요 섹터에 대한 투자자 심리(낙관/중립/비관)를 빠르게 측정하는 주간 펄스 설문입니다.','WEEKLY_SENTIMENT','2026-03-08 23:42:41','2026-03-08 23:42:41','Y'),(17,'2026 미국 주식시장 주요 리스크 인식 조사','트럼프 관세 정책, AI 버블, 연준 독립성 위기 등 2026년 현재 미국 증시에 영향을 미치는 핵심 이슈에 대한 투자자 인식 및 영향도를 조사합니다.','MARKET_RISK_SURVEY','2026-03-14 14:09:47','2026-03-14 14:09:47','Y');
