DROP TABLE IF EXISTS `tbl_survey_answer`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_survey_answer` (
  `answer_id` bigint NOT NULL AUTO_INCREMENT COMMENT '답변 ID',
  `response_id` bigint NOT NULL COMMENT '응답 세션 ID',
  `question_id` bigint NOT NULL COMMENT '문항 ID',
  `selected_option_id` bigint NOT NULL COMMENT '선택한 옵션 ID',
  `selected_value` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '선택 값',
  `answer_score` int DEFAULT NULL COMMENT '답변 점수',
  `answered_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '답변일시',
  PRIMARY KEY (`answer_id`),
  UNIQUE KEY `uk_response_question` (`response_id`,`question_id`),
  KEY `idx_response_id` (`response_id`),
  KEY `idx_question_id` (`question_id`)
) ENGINE=InnoDB AUTO_INCREMENT=415 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='개별 문항 답변 테이블';
/*!40101 SET character_set_client = @saved_cs_client */;

