CREATE TABLE `tbl_survey_option` (
  `option_id` bigint NOT NULL AUTO_INCREMENT COMMENT '옵션 ID',
  `question_id` bigint NOT NULL COMMENT '문항 ID',
  `option_text` varchar(255) COLLATE utf8mb4_general_ci NOT NULL COMMENT '옵션 텍스트',
  `option_value` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '옵션 값',
  `sort_order` int DEFAULT NULL COMMENT '정렬 순서',
  `score` int DEFAULT NULL COMMENT '점수',
  `reg_dt` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  PRIMARY KEY (`option_id`),
  KEY `idx_question_id` (`question_id`)
) ENGINE=InnoDB AUTO_INCREMENT=539 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='선택지 옵션 테이블';
/*!40101 SET character_set_client = @saved_cs_client */;

