DROP TABLE IF EXISTS `tbl_survey_question`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_survey_question` (
  `question_id` bigint NOT NULL AUTO_INCREMENT COMMENT '문항 ID',
  `survey_id` bigint NOT NULL COMMENT '설문 ID',
  `question_number` int NOT NULL COMMENT '설문 내 문항 번호',
  `question_text` varchar(500) COLLATE utf8mb4_general_ci NOT NULL COMMENT '문항 텍스트',
  `question_type_code` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '문항 유형 코드 - QUESTION_TYPE.SINGLE_CHOICE 등',
  `description` text COLLATE utf8mb4_general_ci COMMENT '문항 설명 또는 가이드텍스트',
  `sort_order` int DEFAULT NULL COMMENT '정렬 순서',
  `reg_dt` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '등록일시',
  PRIMARY KEY (`question_id`),
  UNIQUE KEY `uk_survey_question` (`survey_id`,`question_number`),
  KEY `idx_survey_id` (`survey_id`),
  KEY `idx_question_type_code` (`question_type_code`)
) ENGINE=InnoDB AUTO_INCREMENT=117 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='설문 문항 테이블';
/*!40101 SET character_set_client = @saved_cs_client */;

