/*!40000 ALTER TABLE `tbl_survey_question` DISABLE KEYS */;
INSERT INTO `tbl_survey_question` VALUES (61,10,1,'투자 시 가장 중요하게 생각하는 목표는 무엇인가요?','SINGLE_CHOICE','수익추구',1,'2026-03-08 23:42:33'),(62,10,2,'관심 있는 투자 상품의 기대 연 수익률은 얼마인가요?','SINGLE_CHOICE','수익추구',2,'2026-03-08 23:42:33'),(63,10,3,'투자 수익을 실현하는 방식 중 가장 선호하는 것은 무엇인가요?','SINGLE_CHOICE','수익추구',3,'2026-03-08 23:42:33'),(64,10,4,'투자 자산이 -10% 하락했습니다. 어떻게 대응하시겠습니까?','SINGLE_CHOICE','수익추구',4,'2026-03-08 23:42:33'),(65,10,5,'투자 원금 손실을 어느 수준까지 감수할 수 있으신가요?','SINGLE_CHOICE','리스크허용',5,'2026-03-08 23:42:33'),(66,10,6,'가장 편안하게 느껴지는 투자 상품은 무엇인가요?','SINGLE_CHOICE','리스크허용',6,'2026-03-08 23:42:33'),(67,10,7,'현재 투자하려는 자금의 투자 가능 기간은 얼마나 되나요?','SINGLE_CHOICE','리스크허용',7,'2026-03-08 23:42:33'),(68,10,8,'보유 종목이 단기 하락해도 장기 관점에서 유지할 수 있나요?','SINGLE_CHOICE','리스크허용',8,'2026-03-08 23:42:33'),(69,10,9,'보유 종목을 얼마나 자주 점검하고 매매하시나요?','SINGLE_CHOICE','장기투자',9,'2026-03-08 23:42:33'),(70,10,10,'포트폴리오 구성 시 어떤 방식을 선호하시나요?','SINGLE_CHOICE','장기투자',10,'2026-03-08 23:42:33'),(71,10,11,'해외 투자에 대한 생각은 어떠신가요?','SINGLE_CHOICE','장기투자',11,'2026-03-08 23:42:33'),(72,10,12,'투자 자산 배분 시 어떤 원칙을 따르시나요?','SINGLE_CHOICE','장기투자',12,'2026-03-08 23:42:33'),(73,11,1,'트럼프 행정부의 관세 정책이 글로벌 증시에 미치는 영향을 어떻게 전망하시나요?','SINGLE_CHOICE','무역 분쟁 리스크 심리 측정',1,'2026-03-08 23:42:36'),(74,11,2,'향후 6~12개월 내 미국 경기 침체(Recession) 가능성에 대해 어떻게 생각하시나요?','SINGLE_CHOICE','경기 침체 우려 심리 측정',2,'2026-03-08 23:42:36'),(75,11,3,'연준의 2026년 금리 인하 속도와 폭에 대해 어떻게 전망하시나요?','SINGLE_CHOICE','통화정책 기대 심리 측정',3,'2026-03-08 23:42:36'),(76,11,4,'AI 관련 기업의 실적과 반도체 업황 전망은 어떻게 보시나요?','SINGLE_CHOICE','AI·반도체 섹터 심리 측정',4,'2026-03-08 23:42:36'),(77,11,5,'매그니피센트 7(애플·엔비디아·구글 등) 빅테크의 향후 실적 모멘텀을 어떻게 전망하시나요?','SINGLE_CHOICE','빅테크 실적 기대 심리 측정',5,'2026-03-08 23:42:36'),(78,11,6,'중국의 경기 부양책과 소비 회복 속도에 대해 어떻게 전망하시나요?','SINGLE_CHOICE','중국 리스크 심리 측정',6,'2026-03-08 23:42:36'),(79,11,7,'달러 강세 지속과 환율 변동이 신흥국 및 글로벌 증시에 미치는 영향은?','SINGLE_CHOICE','달러·환율 리스크 심리 측정',7,'2026-03-08 23:42:36'),(80,11,8,'위 이슈들을 종합했을 때, 향후 6개월간 글로벌 증시의 방향성은 어떻게 예상하시나요?','SINGLE_CHOICE','종합 시장 심리 측정 (핵심 집계 문항)',8,'2026-03-08 23:42:36'),(81,12,1,'현재 가장 선호하는 투자 섹터는 무엇인가요? (1순위)','SINGLE_CHOICE','1순위 선호 섹터 측정 - 섹터 비중 집계의 핵심 문항',1,'2026-03-08 23:42:38'),(82,12,2,'1순위 다음으로 선호하는 투자 섹터는 무엇인가요? (2순위)','SINGLE_CHOICE','2순위 선호 섹터 측정',2,'2026-03-08 23:42:38'),(83,12,3,'현재 포트폴리오에서 기술주(IT·반도체·AI) 비중은 얼마나 되나요?','SINGLE_CHOICE','기술주 투자 비중 측정',3,'2026-03-08 23:42:38'),(84,12,4,'현재 포트폴리오에서 헬스케어(바이오·제약·의료기기) 비중은 얼마나 되나요?','SINGLE_CHOICE','헬스케어 투자 비중 측정',4,'2026-03-08 23:42:38'),(85,12,5,'현재 포트폴리오에서 소비재(필수·경기소비재) 비중은 얼마나 되나요?','SINGLE_CHOICE','소비재 투자 비중 측정',5,'2026-03-08 23:42:38'),(86,12,6,'현재 포트폴리오에서 에너지(정유·전기차·신재생에너지) 비중은 얼마나 되나요?','SINGLE_CHOICE','에너지 투자 비중 측정',6,'2026-03-08 23:42:38'),(87,12,7,'현재 포트폴리오에서 금융(은행·증권·보험) 비중은 얼마나 되나요?','SINGLE_CHOICE','금융 투자 비중 측정',7,'2026-03-08 23:42:38'),(88,12,8,'향후 6개월간 가장 유망하다고 생각하는 섹터는 어디인가요?','SINGLE_CHOICE','향후 유망 섹터 1순위 측정 - 차트의 수익률 변화 연동',8,'2026-03-08 23:42:38'),(89,12,9,'향후 6개월간 가장 리스크가 크다고 생각하는 섹터는 어디인가요?','SINGLE_CHOICE','위험 섹터 인식 측정',9,'2026-03-08 23:42:38'),(90,12,10,'현재 포트폴리오의 섹터 배분을 어떻게 변경할 계획인가요?','SINGLE_CHOICE','섹터 리밸런싱 의향 측정',10,'2026-03-08 23:42:38'),(91,13,1,'이번 주 기술주(AI·반도체·빅테크)에 대한 투자 심리는 어떠신가요?','SINGLE_CHOICE','기술주 주간 심리 핵심 집계 문항 - 낙관/중립/비관 비율 산출',1,'2026-03-08 23:42:41'),(92,13,2,'지난주 대비 기술주에 대한 심리가 어떻게 변화했나요?','SINGLE_CHOICE','주간 심리 변화 방향 측정 - 트렌드 차트의 주간 등락 연동',2,'2026-03-08 23:42:41'),(93,13,3,'이번 주 기술주 심리에 가장 큰 영향을 미친 요인은 무엇인가요?','SINGLE_CHOICE','심리 변화 원인 분석 - 주간 코멘트 리포트 활용',3,'2026-03-08 23:42:41'),(94,13,4,'이번 주 가장 주목한 기술주 관련 이벤트는 무엇인가요?','SINGLE_CHOICE','이슈 트래킹 - 섹터 이슈 태그 연동',4,'2026-03-08 23:42:41'),(95,13,5,'현재 기술주에 대해 어떤 투자 행동을 취하고 계신가요?','SINGLE_CHOICE','실제 투자 행동 측정 - 심리와 행동 괴리 분석',5,'2026-03-08 23:42:41'),(96,13,6,'다음 주 기술주 주가 방향성을 어떻게 예상하시나요?','SINGLE_CHOICE','단기 전망 측정 - 다음 주 심리 선행 지표',6,'2026-03-08 23:42:41'),(97,13,7,'이번 주 기술주를 제외한 전체 시장 심리는 어떠신가요?','SINGLE_CHOICE','전체 시장 심리 비교 측정 - 기술주 심리와 시장 심리 괴리 파악',7,'2026-03-08 23:42:41'),(110,17,1,'트럼프 행정부의 추가 관세 정책이 미국 주식시장에 미치는 영향을 어떻게 평가하시나요?','SINGLE_CHOICE','2026년 트럼프 대통령은 기존 중국 관세에 더해 추가 관세를 부과하며 시장 변동성을 키우고 있습니다. 해당 정책이 기업 실적 및 주가에 미치는 영향을 선택해 주세요.',1,'2026-03-14 14:09:47'),(111,17,2,'AI 버블 붕괴 가능성이 미국 증시 전반에 미칠 파급력을 어느 수준으로 보시나요?','SINGLE_CHOICE','Nvidia 등 AI 인프라 기업의 주가가 고공행진 중이지만, AI 투자 대비 실질 수익 창출이 아직 불투명하다는 우려가 제기되고 있습니다. 버블 붕괴 시 증시에 미칠 영향을 선택해 주세요.',2,'2026-03-14 14:09:47'),(112,17,3,'2026년 5월 파월 연준 의장 임기 만료 후 차기 의장 교체가 주식시장에 미치는 리스크 수준은?','SINGLE_CHOICE','트럼프 대통령은 공격적인 금리 인하를 원하고 있으며, 파월 임기 종료 후 차기 의장의 성향에 따라 연준의 독립성 및 통화정책 방향이 크게 달라질 수 있습니다.',3,'2026-03-14 14:09:47'),(113,17,4,'현재 S&P 500의 밸류에이션(CAPE 기준 역사적 고점 수준)이 향후 주가에 미칠 영향은 무엇이라고 생각하시나요?','SINGLE_CHOICE','S&P 500의 경기조정 주가수익비율(CAPE Ratio)은 현재 역사적으로 두 번째로 높은 수준입니다. 이 고평가 상태가 향후 시장에 어떤 영향을 미칠지 선택해 주세요.',4,'2026-03-14 14:09:47'),(114,17,5,'2026년 S&P 500 기업들의 EPS 성장률 전망(약 14.5%)이 실제로 달성될 가능성을 어떻게 보시나요?','SINGLE_CHOICE','월스트리트 애널리스트들은 2026년 S&P 500 기업들의 주당순이익(EPS)이 전년 대비 약 14.5% 성장할 것으로 전망합니다. 관세·금리 등 불확실성 속에서 이 전망의 현실성을 평가해 주세요.',5,'2026-03-14 14:09:47'),(115,17,6,'미중 무역갈등 심화 및 글로벌 지정학적 리스크가 미국 주식시장에 미치는 영향 강도는?','SINGLE_CHOICE','미국의 대중국 첨단 반도체 수출 제한, 글로벌 분쟁 장기화 등 지정학적 변수가 증시에 미치는 영향을 평가해 주세요.',6,'2026-03-14 14:09:47'),(116,17,7,'위의 모든 리스크 요인을 종합할 때, 2026년 하반기 미국 주식시장의 방향성을 어떻게 전망하시나요?','SINGLE_CHOICE','관세, AI 버블, 연준 리스크, 밸류에이션, 기업 실적, 지정학적 리스크 등을 종합적으로 고려한 하반기 증시 방향성을 선택해 주세요.',7,'2026-03-14 14:09:47');
/*!40000 ALTER TABLE `tbl_survey_question` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `tbl_survey_result`
--

DROP TABLE IF EXISTS `tbl_survey_result`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tbl_survey_result` (
  `result_id` bigint NOT NULL AUTO_INCREMENT COMMENT '분석 결과 ID',
  `user_id` varchar(50) COLLATE utf8mb4_general_ci NOT NULL COMMENT '사용자 ID',
  `survey_id` bigint NOT NULL COMMENT '설문 ID',
  `risk_score` int DEFAULT NULL COMMENT '위험 점수 (0~100)',
  `risk_level_code` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '위험 레벨 코드 - RISK_LEVEL.CONSERVATIVE 등',
  `recommendation` text COLLATE utf8mb4_general_ci COMMENT '투자 추천사항',
  `portfolio_suggestion` varchar(500) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '추천 포트폴리오 구성',
  `analyzed_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '분석 일시',
  `valid_until` datetime DEFAULT NULL COMMENT '분석 결과 유효 기간',
  `use_yn` char(1) COLLATE utf8mb4_general_ci DEFAULT 'N' COMMENT '결과 사용 여부',
  PRIMARY KEY (`result_id`),
  KEY `idx_user_survey_result` (`user_id`,`survey_id`),
  KEY `idx_valid_until` (`valid_until`),
  KEY `idx_risk_level_code` (`risk_level_code`)
) ENGINE=InnoDB AUTO_INCREMENT=59 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='설문 결과 분석 테이블';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `tbl_survey_result`
--

