--
-- Table structure for table `user_alerts`
--

DROP TABLE IF EXISTS `user_alerts`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `user_alerts` (
  `alert_id` bigint NOT NULL AUTO_INCREMENT COMMENT '알림 설정 고유 ID',
  `user_id` bigint NOT NULL COMMENT '사용자 ID',
  `alert_type` enum('sector','news','company','market') NOT NULL COMMENT '알림 유형 (섹터/뉴스/기업/시장)',
  `target_id` varchar(50) DEFAULT NULL COMMENT '알림 대상 ID (sector_id, symbol 등)',
  `threshold_value` decimal(5,2) DEFAULT NULL COMMENT '알림 발생 임계값 (예: 변동률 5% 이상)',
  `is_active` tinyint(1) DEFAULT '1' COMMENT '알림 활성화 여부',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '레코드 생성 시각',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '레코드 수정 시각',
  PRIMARY KEY (`alert_id`),
  KEY `idx_user_id` (`user_id`) COMMENT '사용자 ID 기준 조회 최적화',
  KEY `idx_alert_type` (`alert_type`) COMMENT '알림 유형 기준 조회 최적化'
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='사용자별 맞춤 알림 설정 데이터';
/*!40101 SET character_set_client = @saved_cs_client */;

